Certainly! Below is a simple implementation of a **Stack** data structure in Java using an array. The class provides basic stack operations: `push`, `pop`, `peek`, `isEmpty`, and `size`.

```java
public class Stack {
    private int[] data;
    private int top;
    private int capacity;

    // Constructor to initialize the stack
    public Stack(int size) {
        capacity = size;
        data = new int[capacity];
        top = -1;
    }

    // Pushes an element onto the stack
    public void push(int value) {
        if (top == capacity - 1) {
            throw new RuntimeException("Stack Overflow");
        }
        data[++top] = value;
    }

    // Pops the top element from the stack
    public int pop() {
        if (isEmpty()) {
            throw new RuntimeException("Stack Underflow");
        }
        return data[top--];
    }

    // Returns the top element without removing it
    public int peek() {
        if (isEmpty()) {
            throw new RuntimeException("Stack is empty");
        }
        return data[top];
    }

    // Checks if the stack is empty
    public boolean isEmpty() {
        return top == -1;
    }

    // Returns the number of elements in the stack
    public int size() {
        return top + 1;
    }

    // Main method for demonstration
    public static void main(String[] args) {
        Stack stack = new Stack(5);

        stack.push(10);
        stack.push(20);
        stack.push(30);

        System.out.println("Top element: " + stack.peek()); // 30
        System.out.println("Stack size: " + stack.size());  // 3

        System.out.println("Popped: " + stack.pop());       // 30
        System.out.println("Stack size: " + stack.size());  // 2
    }
}
```

**Explanation:**
- The `Stack` class uses an integer array to store elements.
- The `top` variable keeps track of the index of the top element.
- The class provides methods to manipulate and inspect the stack.
- The `main` method demonstrates basic usage.

Certainly! Below is a simple C++ library implementing a singly linked list. The library provides basic operations such as insertion, deletion, search, and display. You can extend it as needed.

**linked_list.h**
```cpp
#ifndef LINKED_LIST_H
#define LINKED_LIST_H

#include <iostream>

template <typename T>
class LinkedList {
private:
    struct Node {
        T data;
        Node* next;
        Node(const T& val) : data(val), next(nullptr) {}
    };
    Node* head;

public:
    LinkedList() : head(nullptr) {}
    ~LinkedList();

    void insert_front(const T& value);
    void insert_back(const T& value);
    bool remove(const T& value);
    bool search(const T& value) const;
    void display() const;
    void clear();
    bool empty() const;
};

template <typename T>
LinkedList<T>::~LinkedList() {
    clear();
}

template <typename T>
void LinkedList<T>::insert_front(const T& value) {
    Node* new_node = new Node(value);
    new_node->next = head;
    head = new_node;
}

template <typename T>
void LinkedList<T>::insert_back(const T& value) {
    Node* new_node = new Node(value);
    if (!head) {
        head = new_node;
        return;
    }
    Node* curr = head;
    while (curr->next) {
        curr = curr->next;
    }
    curr->next = new_node;
}

template <typename T>
bool LinkedList<T>::remove(const T& value) {
    Node* curr = head;
    Node* prev = nullptr;
    while (curr) {
        if (curr->data == value) {
            if (prev) {
                prev->next = curr->next;
            } else {
                head = curr->next;
            }
            delete curr;
            return true;
        }
        prev = curr;
        curr = curr->next;
    }
    return false;
}

template <typename T>
bool LinkedList<T>::search(const T& value) const {
    Node* curr = head;
    while (curr) {
        if (curr->data == value)
            return true;
        curr = curr->next;
    }
    return false;
}

template <typename T>
void LinkedList<T>::display() const {
    Node* curr = head;
    while (curr) {
        std::cout << curr->data << " -> ";
        curr = curr->next;
    }
    std::cout << "NULL\n";
}

template <typename T>
void LinkedList<T>::clear() {
    Node* curr = head;
    while (curr) {
        Node* temp = curr;
        curr = curr->next;
        delete temp;
    }
    head = nullptr;
}

template <typename T>
bool LinkedList<T>::empty() const {
    return head == nullptr;
}

#endif // LINKED_LIST_H
```

**Example usage:**
```cpp
#include "linked_list.h"

int main() {
    LinkedList<int> list;
    list.insert_back(10);
    list.insert_front(5);
    list.insert_back(20);
    list.display(); // Output: 5 -> 10 -> 20 -> NULL

    list.remove(10);
    list.display(); // Output: 5 -> 20 -> NULL

    if (list.search(20)) {
        std::cout << "Found 20\n";
    }
    list.clear();
    list.display(); // Output: NULL
    return 0;
}
```

**How to use:**
- Save the header as `linked_list.h`.
- Include it in your project.
- Use the `LinkedList<T>` class for your desired type.

