    ones = ["zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"]
    teens = ["ten", "eleven", "twelve", "thirteen", "fourteen", "fifteen", "sixteen", "seventeen", "eighteen", "nineteen"]
    tens = ["", "", "twenty", "thirty", "forty", "fifty", "sixty", "seventy", "eighty", "ninety"]

    def two_digits(num):
        if num < 10:
            return ones[num]
        elif 10 <= num < 20:
            return teens[num - 10]
        else:
            ten = num // 10
            one = num % 10
            if one == 0:
                return tens[ten]
            else:
                return tens[ten] + "-" + ones[one]

    def three_digits(num):
        hundred = num // 100
        rest = num % 100
        if hundred == 0:
            return two_digits(rest)
        elif rest == 0:
            return ones[hundred] + " hundred"
        else:
            return ones[hundred] + " hundred and " + two_digits(rest)

    thousand = n // 1000
    rest = n % 1000

    words = ""
    if thousand > 0:
        words += ones[thousand] + " thousand"
        if rest > 0:
            if rest < 100:
                words += " and "
            else:
                words += " "
    if rest > 0 or n == 0:
        words += three_digits(rest)
    return words

# Example usage:
num = int(input("Enter a number between 0 and 9999: "))
print(number_to_words(num))
